@file:Suppress("LargeClass", "TooManyFunctions")
package com.hushtv.tv.data

import androidx.compose.ui.graphics.Color

/**
 * Auto-generated catalog of decades → years → top-popular movie titles.
 *
 * Generated from TMDB on 2026-05-03 via:
 *   /discover/movie?primary_release_year=YYYY&sort_by=popularity.desc
 *
 * • 9 decades: 1940s through 2020s (covers 1940 → 2029).
 * • Each year: up to 250 most-popular movies as ranked by TMDB at
 *   build time. Sufficient to surface every single mainstream
 *   release in the user's Xtream library.
 * • Year ordering is preserved (popularity descending) so when
 *   matched against [LibraryIndex], the resulting grid is sorted
 *   "most popular first" with no extra sort step at runtime.
 *
 * Static data is intentional. The library matcher does ALL the
 * filtering — the user only ever sees titles they actually own.
 *
 * To regenerate: re-run /tmp/fetch_decade_years.py and
 * /tmp/build_decade_kotlin.py against the latest TMDB.
 */

/** A single year inside a decade — its top popular titles. */
data class HushYear(
    val year: Int,
    /** Movie titles, popularity descending. Fed to LibraryIndex.findBest. */
    val movies: List<String>,
    /** Hardcoded TMDB CDN URL of the year's #1 popular film. */
    val backdropUrl: String?,
)

/** A 10-year span with its constituent years + an iconic decade backdrop. */
data class HushDecade(
    /** Start year of the decade (e.g. 1990 for "The 1990s"). */
    val startYear: Int,
    /** Display label, e.g. "1990s". */
    val label: String,
    /** Marketing title, e.g. "The Independent Boom". */
    val title: String,
    /** One-line subtitle. */
    val subtitle: String,
    /** Decade accent color for highlights / focus rings. */
    val accent: Color,
    /** TMDB CDN URL of the decade's most iconic film (full backdrop). */
    val heroBackdropUrl: String?,
    /** All 10 years in the decade, oldest → newest. */
    val years: List<HushYear>,
)

object HushDecadeYears {

    private const val TMDB_BASE = "https://image.tmdb.org/t/p/original"

    private val Amber   = Color(0xFFF59E0B)
    private val Crimson = Color(0xFFDC2626)
    private val Indigo  = Color(0xFF6366F1)
    private val Orange  = Color(0xFFF97316)
    private val Violet  = Color(0xFF8B5CF6)
    private val Teal    = Color(0xFF14B8A6)
    private val Azure   = Color(0xFF3B82F6)
    private val Mint    = Color(0xFF10B981)
    private val Sky     = Color(0xFF38BDF8)

    /** Convenience for the data builder. */
    private fun y(year: Int, movies: List<String>, backdrop: String?) =
        HushYear(
            year = year,
            movies = movies,
            backdropUrl = backdrop?.let { "$TMDB_BASE$it" },
        )


