    val all: List<HushDecade> = listOf(
        build1940s(),
        build1950s(),
        build1960s(),
        build1970s(),
        build1980s(),
        build1990s(),
        build2000s(),
        build2010s(),
        build2020s(),
    )


    /** Locate a decade by its start year (1940, 1950, ...). null if invalid. */
    fun decadeOf(startYear: Int): HushDecade? =
        all.firstOrNull { it.startYear == startYear }

    /** Locate a single year across all decades. null if outside 1940-2029. */
    fun year(year: Int): HushYear? {
        val decade = all.firstOrNull { year in it.startYear..(it.startYear + 9) }
            ?: return null
        return decade.years.firstOrNull { it.year == year }
    }
